auto tree_stuff(const auto &amp;g, size_t root) {
size_t n = size(g), tn = 0;
vector&lt;size_t&gt; par(n,-1), tin(n), tout(n);
function&lt;void(size_t)&gt; go = [&amp;](size_t v) {
tin[v] = tn++;
for(size_t i : g[v]) if(i!=par[v]) {
par[i] = v;
go(i);
}
tout[v] = tn;
};
go(root);
return tuple(tin, tout);
}


